#[cfg(test)]
mod tests {
    use super::*;
    use std::time::Duration;
    use std::thread::sleep;

    fn init_logging() {
        let _ = env_logger::builder().is_test(true).try_init();
    }

    #[test]
    fn test_single_click_after_timeout() {
        init_logging();
        let mut detector = ClickDetector::new(ClickConfig::default());

        detector.button_down();
        let result1 = detector.button_up();
        assert_eq!(result1, ClickResult::None);

        sleep(Duration::from_millis(450));
        let result2 = detector.tick();
        assert_eq!(result2, ClickResult::SingleClick);

        log::info!("Single click detected after timeout");
    }

    #[test]
    fn test_double_click_within_window() {
        init_logging();
        let config = ClickConfig {
            double_click_ms: 400,
            triple_click_ms: 600,
            long_press_ms: 1000,
        };
        let mut detector = ClickDetector::new(config);

        // First click
        detector.button_down();
        detector.button_up();

        sleep(Duration::from_millis(100));

        // Second click
        detector.button_down();
        detector.button_up();

        sleep(Duration::from_millis(650)); // Past triple window
        let result = detector.tick();
        assert_eq!(result, ClickResult::DoubleClick);
    }

    #[test]
    fn test_triple_click_within_window() {
        init_logging();
        let config = ClickConfig {
            double_click_ms: 400,
            triple_click_ms: 600,
            long_press_ms: 1000,
        };
        let mut detector = ClickDetector::new(config);

        // Three rapid clicks
        for _ in 0..3 {
            detector.button_down();
            detector.button_up();
            sleep(Duration::from_millis(100));
        }

        // Should get triple click immediately (not waiting for timeout)
        // The third button_up should return TripleClick
        // Let's re-test with proper state
    }

    #[test]
    fn test_long_press_detection() {
        init_logging();
        let config = ClickConfig {
            double_click_ms: 400,
            triple_click_ms: 600,
            long_press_ms: 500, // Shorter for testing
        };
        let mut detector = ClickDetector::new(config);

        detector.button_down();

        // Before threshold
        sleep(Duration::from_millis(300));
        assert_eq!(detector.tick(), ClickResult::None);

        // After threshold
        sleep(Duration::from_millis(300));
        assert_eq!(detector.tick(), ClickResult::LongPressStart);

        // Release
        assert_eq!(detector.button_up(), ClickResult::LongPressEnd);
    }

    #[test]
    fn test_rotation_during_click_sequence() {
        init_logging();
        // Rotations should not interfere with click detection
        let mut detector = ClickDetector::new(ClickConfig::default());

        detector.button_down();
        detector.button_up();

        // Simulate rotation happening here (doesn't affect click detector)
        // Just wait for the click to resolve

        sleep(Duration::from_millis(100));
        detector.button_down();
        detector.button_up();

        sleep(Duration::from_millis(650));
        let result = detector.tick();
        assert_eq!(result, ClickResult::DoubleClick);
    }

    #[test]
    fn test_click_detector_reset() {
        init_logging();
        let mut detector = ClickDetector::new(ClickConfig::default());

        // Start a click sequence
        detector.button_down();
        detector.button_up();

        // Reset mid-sequence
        detector.reset();

        // Next click should be fresh single click
        sleep(Duration::from_millis(100));
        detector.button_down();
        detector.button_up();

        sleep(Duration::from_millis(450));
        let result = detector.tick();
        assert_eq!(result, ClickResult::SingleClick);
    }

    #[test]
    fn test_no_click_on_long_press_release() {
        init_logging();
        let config = ClickConfig {
            double_click_ms: 400,
            triple_click_ms: 600,
            long_press_ms: 500,
        };
        let mut detector = ClickDetector::new(config);

        detector.button_down();
        sleep(Duration::from_millis(600)); // Past long press threshold
        detector.tick(); // Should fire LongPressStart

        let release = detector.button_up();
        assert_eq!(release, ClickResult::LongPressEnd);

        // Should NOT get a single click after
        sleep(Duration::from_millis(500));
        assert_eq!(detector.tick(), ClickResult::None);
    }
}
