```rust
#[cfg(test)]
mod tests {
    use super::*;

    fn init_logging() {
        let _ = env_logger::builder().is_test(true).try_init();
    }

    #[test]
    fn test_linear_curve_identity() {
        init_logging();
        let curve = LinearCurve;

        for i in 0..=100 {
            assert_eq!(curve.apply(i), i, "Linear curve should be identity");
            assert_eq!(curve.inverse(i), i, "Linear inverse should be identity");
        }
    }

    #[test]
    fn test_curve_endpoints() {
        init_logging();
        let curves: Vec<Box<dyn VolumeCurve>> = vec![
            Box::new(LinearCurve),
            Box::new(LogarithmicCurve::default()),
            Box::new(ExponentialCurve::default()),
        ];

        for curve in curves {
            assert_eq!(curve.apply(0), 0, "{} should map 0 -> 0", curve.name());
            assert_eq!(curve.apply(100), 100, "{} should map 100 -> 100", curve.name());
            assert_eq!(curve.inverse(0), 0, "{} inverse should map 0 -> 0", curve.name());
            assert_eq!(curve.inverse(100), 100, "{} inverse should map 100 -> 100", curve.name());
        }
    }

    #[test]
    fn test_logarithmic_curve_midpoint() {
        init_logging();
        let curve = LogarithmicCurve::default();

        // At 50% dial position, logarithmic curve should give > 50% volume
        let mid = curve.apply(50);
        assert!(mid > 50, "Logarithmic curve at 50% dial should give > 50% volume, got {}", mid);
        assert!(mid < 80, "Logarithmic curve at 50% dial should give < 80% volume, got {}", mid);

        log::info!("Logarithmic curve: 50% dial -> {}% volume", mid);
    }

    #[test]
    fn test_curve_inverse_roundtrip() {
        init_logging();
        let curves: Vec<Box<dyn VolumeCurve>> = vec![
            Box::new(LinearCurve),
            Box::new(LogarithmicCurve::default()),
            Box::new(ExponentialCurve::default()),
        ];

        for curve in curves {
            for dial in (0..=100).step_by(5) {
                let volume = curve.apply(dial);
                let back = curve.inverse(volume);
                let diff = (back - dial).abs();
                assert!(diff <= 1, "{}: inverse({}) = {} != original dial {}", 
                    curve.name(), volume, back, dial);
            }
            log::info!("{} curve passed roundtrip test", curve.name());
        }
    }

    #[test]
    fn test_logarithmic_steepness_effect() {
        init_logging();
        let shallow = LogarithmicCurve { steepness: 2.0 };
        let steep = LogarithmicCurve { steepness: 15.0 };

        let shallow_mid = shallow.apply(50);
        let steep_mid = steep.apply(50);

        // Steeper curve should give higher volume at midpoint
        assert!(steep_mid > shallow_mid, 
            "Steeper curve should give higher volume at midpoint: {} > {}", steep_mid, shallow_mid);

        log::info!("Steepness 2.0 at 50%: {}, Steepness 15.0 at 50%: {}", shallow_mid, steep_mid);
    }

    #[test]
    fn test_custom_curve_interpolation() {
        init_logging();
        let curve = CustomCurve::new(vec![
            (0, 0),
            (50, 25),  // 50% dial = 25% volume (quiet curve)
            (100, 100),
        ]);

        assert_eq!(curve.apply(0), 0);
        assert_eq!(curve.apply(50), 25);
        assert_eq!(curve.apply(100), 100);

        // Test interpolation
        let mid = curve.apply(25);
        assert!(mid >= 10 && mid <= 15, "Interpolation at 25% should be ~12, got {}", mid);
    }

    #[test]
    fn test_curve_clamping() {
        init_logging();
        let curve = LogarithmicCurve::default();

        // Out of range inputs should be clamped
        assert_eq!(curve.apply(-10), 0);
        assert_eq!(curve.apply(150), 100);
        assert_eq!(curve.inverse(-10), 0);
        assert_eq!(curve.inverse(150), 100);
    }
}
