### 5. Sensitivity Tests (`src/input/sensitivity.rs`)

```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_dead_zone_accumulation() {
        let mut sens = SensitivityConfig {
            dead_zone: 3,
            multiplier: 1.0,
            invert: false,
            accumulated: 0,
        };

        // Small rotations should be absorbed
        assert_eq!(sens.process(1), None);
        assert_eq!(sens.process(1), None);
        assert_eq!(sens.process(1), None);

        // Fourth should trigger (accumulated = 4, threshold = 3)
        let result = sens.process(1);
        assert!(result.is_some());
        assert_eq!(result.unwrap(), 1); // 4 - 3 = 1
    }

    #[test]
    fn test_dead_zone_bidirectional() {
        let mut sens = SensitivityConfig {
            dead_zone: 3,
            multiplier: 1.0,
            invert: false,
            accumulated: 0,
        };

        // Oscillating rotations should cancel out
        sens.process(2);  // accumulated = 2
        sens.process(-2); // accumulated = 0
        sens.process(2);  // accumulated = 2

        // Still within dead zone
        assert_eq!(sens.accumulated, 2);
    }

    #[test]
    fn test_multiplier_scaling() {
        let mut sens = SensitivityConfig {
            dead_zone: 0,
            multiplier: 2.0,
            invert: false,
            accumulated: 0,
        };

        assert_eq!(sens.process(5), Some(10)); // 5 * 2.0 = 10

        sens.multiplier = 0.5;
        assert_eq!(sens.process(4), Some(2)); // 4 * 0.5 = 2
    }

    #[test]
    fn test_invert_direction() {
        let mut sens = SensitivityConfig {
            dead_zone: 0,
            multiplier: 1.0,
            invert: true,
            accumulated: 0,
        };

        assert_eq!(sens.process(5), Some(-5));
        assert_eq!(sens.process(-3), Some(3));
    }

    #[test]
    fn test_reset_clears_accumulator() {
        let mut sens = SensitivityConfig {
            dead_zone: 5,
            multiplier: 1.0,
            invert: false,
            accumulated: 0,
        };

        sens.process(3); // accumulated = 3
        sens.reset();
        assert_eq!(sens.accumulated, 0);
    }

    #[test]
    fn test_presets() {
        let acc = SensitivityConfig::accessibility();
        assert!(acc.dead_zone >= 2, "Accessibility should have dead zone");
        assert!(acc.multiplier < 1.0, "Accessibility should be less sensitive");

        let fast = SensitivityConfig::fast();
        assert_eq!(fast.dead_zone, 0, "Fast should have no dead zone");
        assert!(fast.multiplier > 1.0, "Fast should be more sensitive");

        let precision = SensitivityConfig::precision();
        assert!(precision.multiplier < 1.0, "Precision should be less sensitive");
    }
}
