#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_battery_low_thresholds() {
        let status = BatteryStatus {
            percent: Some(15),
            charging: false,
            minutes_remaining: None,
        };

        assert!(status.is_low(20));
        assert!(!status.is_low(10));
        assert!(status.is_critical()); // <10% is critical

        // Actually 15% is not critical (<10)
        let status15 = BatteryStatus { percent: Some(15), charging: false, minutes_remaining: None };
