#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::sync::Arc;

    #[test]
    fn test_event_payload_json() {
        let payload = EventPayload::new(DaemonEvent::VolumeChange {
            old_volume: 50,
            new_volume: 55,
            mode: "volume".to_string(),
        });

        let json = payload.to_json();
        assert!(json.contains("volume_change"));
        assert!(json.contains("\"old_volume\":50"));
        assert!(json.contains("\"new_volume\":55"));
    }

    #[test]
    fn test_event_env_vars_complete() {
        let payload = EventPayload::new(DaemonEvent::VolumeChange {
            old_volume: 50,
            new_volume: 55,
            mode: "volume".to_string(),
        });

        let vars = payload.to_env_vars();

        let var_map: std::collections::HashMap<_, _> = vars.into_iter().collect();
        assert_eq!(var_map.get("DIAL_EVENT_TYPE"), Some(&"volume_change".to_string()));
        assert_eq!(var_map.get("DIAL_OLD_VOLUME"), Some(&"50".to_string()));
        assert_eq!(var_map.get("DIAL_NEW_VOLUME"), Some(&"55".to_string()));
        assert_eq!(var_map.get("DIAL_MODE"), Some(&"volume".to_string()));
        assert!(var_map.contains_key("DIAL_TIMESTAMP"));
    }

    #[test]
    fn test_all_event_types_serialize() {
        let events = vec![
            DaemonEvent::VolumeChange { old_volume: 50, new_volume: 55, mode: "volume".into() },
            DaemonEvent::ModeChange { old_mode: "volume".into(), new_mode: "microphone".into() },
            DaemonEvent::MuteToggle { muted: true, mode: "volume".into() },
            DaemonEvent::Click { click_type: "double".into() },
            DaemonEvent::DeviceSwitch { old_device: "Speakers".into(), new_device: "Headphones".into() },
            DaemonEvent::ConnectionChange { connected: true },
            DaemonEvent::BatteryChange { old_percent: Some(80), new_percent: 75 },
        ];

        for event in events {
            let payload = EventPayload::new(event);
            let json = payload.to_json();
            assert!(!json.is_empty());
            assert!(json.starts_with('{'));
            assert!(json.ends_with('}'));
        }
    }
}
