#[derive(Args)]
pub struct ConfigArgs {
    #[command(subcommand)]
    pub command: Option<ConfigCommand>,

    #[arg(long)]
    pub json: bool,
}

#[derive(Subcommand)]
pub enum ConfigCommand {
    Get { key: String, #[arg(long)] json: bool },
    Set { key: String, value: String, #[arg(long)] json: bool },
    Reset { #[arg(long)] confirm: bool },
    Path,
    ShowCurve,
    Keys { #[arg(long)] json: bool },
}

pub fn run(args: ConfigArgs) -> Result<(), Box<dyn std::error::Error>> {
    let config = Config::load();

    match args.command {
        None => show_all_config(&config, args.json),
        Some(ConfigCommand::Get { key, json }) => get_value(&config, &key, json),
        Some(ConfigCommand::Set { key, value, json }) => set_value(key, value, json),
        Some(ConfigCommand::Reset { confirm }) => reset_config(confirm),
        Some(ConfigCommand::Path) => println!("{}", Config::path().display()),
        Some(ConfigCommand::ShowCurve) => show_volume_curve(&config),
        Some(ConfigCommand::Keys { json }) => list_keys(json),
    }

    Ok(())
}

