fn show_volume_curve(config: &Config) {
    let curve = crate::audio::create_volume_curve(&config.volume);

    println!("Volume Curve: {} (steepness: {:.1})\n", config.volume.curve, config.volume.curve_steepness);
    println!("Actual Volume");

    for y in (0..=10).rev() {
        let y_val = y * 10;
        print!("{:3}% │", y_val);

        for x in 0..=20 {
            let x_val = x * 5;
            let actual = curve.apply(x_val);
            if (actual as i32 - y_val as i32).abs() <= 5 {
                print!("●");
            } else if actual > y_val {
                print!(" ");
            } else {
                print!("░");
            }
        }
        println!();
    }

    println!("     └────────────────────────");
    println!("      0%   25%   50%   75%  100%");
    println!("           Dial Position");
}

