## Implementation

### Logger Setup

```rust
// src/logging.rs
use log::{Level, LevelFilter, Metadata, Record, Log};
use std::fs::{File, OpenOptions};
use std::io::{Write, BufWriter};
use std::path::PathBuf;
use std::sync::Mutex;
use chrono::Local;

pub struct DualLogger {
    console_level: LevelFilter,
    file_level: LevelFilter,
    file: Option<Mutex<RotatingFile>>,
    json_mode: bool,
}

pub struct RotatingFile {
    writer: BufWriter<File>,
    path: PathBuf,
    current_size: u64,
    max_size: u64,
    keep_files: u32,
}

impl RotatingFile {
    pub fn new(path: PathBuf, max_size_mb: u32, keep_files: u32) -> std::io::Result<Self> {
        let max_size = (max_size_mb as u64) * 1024 * 1024;

        // Ensure parent directory exists
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }

        let file = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&path)?;

        let current_size = file.metadata()?.len();

        Ok(Self {
            writer: BufWriter::new(file),
            path,
            current_size,
            max_size,
            keep_files,
        })
    }

    pub fn write(&mut self, data: &[u8]) -> std::io::Result<()> {
        // Check if rotation needed
        if self.current_size + data.len() as u64 > self.max_size {
            self.rotate()?;
        }

        self.writer.write_all(data)?;
        self.writer.flush()?;
        self.current_size += data.len() as u64;
        Ok(())
    }

    fn rotate(&mut self) -> std::io::Result<()> {
        // Close current file
        self.writer.flush()?;

        // Rotate existing files
        for i in (1..self.keep_files).rev() {
            let old_path = self.rotated_path(i);
            let new_path = self.rotated_path(i + 1);
            if old_path.exists() {
                if i + 1 > self.keep_files {
                    std::fs::remove_file(&old_path)?;
                } else {
                    std::fs::rename(&old_path, &new_path)?;
                }
            }
        }

        // Rename current to .1
        if self.path.exists() {
            std::fs::rename(&self.path, self.rotated_path(1))?;
        }

        // Create new file
        let file = OpenOptions::new()
            .create(true)
            .write(true)
            .truncate(true)
            .open(&self.path)?;

        self.writer = BufWriter::new(file);
        self.current_size = 0;

        Ok(())
    }

    fn rotated_path(&self, n: u32) -> PathBuf {
        let mut path = self.path.clone();
        let filename = path.file_name()
            .unwrap_or_default()
            .to_string_lossy()
            .to_string();
        path.set_file_name(format!("{}.{}", filename, n));
        path
    }
}

impl DualLogger {
    pub fn init(config: &crate::config::DaemonConfig) -> Result<(), log::SetLoggerError> {
        let level = match config.log_level.to_lowercase().as_str() {
            "error" => LevelFilter::Error,
            "warn" => LevelFilter::Warn,
            "info" => LevelFilter::Info,
            "debug" => LevelFilter::Debug,
            "trace" => LevelFilter::Trace,
            _ => LevelFilter::Info,
        };

        let file = if config.log_file_enabled {
            let log_path = dirs::data_local_dir()
                .unwrap_or_else(|| PathBuf::from("."))
                .join("surface-dial")
                .join("daemon.log");

            RotatingFile::new(
                log_path,
                config.log_max_size_mb,
                config.log_keep_files,
            ).ok().map(Mutex::new)
        } else {
            None
        };

        let logger = Self {
            console_level: level,
            file_level: level,
            file,
            json_mode: false,
        };

        log::set_boxed_logger(Box::new(logger))?;
        log::set_max_level(level);
        Ok(())
    }

    fn format_console(&self, record: &Record) -> String {
        let timestamp = Local::now().format("%Y-%m-%d %H:%M:%S%.3f");
        let level = record.level();
        let target = record.target();
        let message = record.args();

        let color = match level {
            Level::Error => "\x1b[31m", // Red
            Level::Warn => "\x1b[33m",  // Yellow
            Level::Info => "\x1b[32m",  // Green
            Level::Debug => "\x1b[36m", // Cyan
            Level::Trace => "\x1b[90m", // Gray
        };

        format!("{color}[{timestamp}] [{level:5}] [{target}] {message}\x1b[0m\n")
    }

    fn format_file(&self, record: &Record) -> String {
        let timestamp = Local::now().format("%Y-%m-%d %H:%M:%S%.3f");
        let level = record.level();
        let target = record.target();
        let message = record.args();

        if self.json_mode {
            // Structured JSON output
            format!(
                r#"{{"timestamp":"{}","level":"{}","target":"{}","message":"{}"}}"#,
                timestamp,
                level,
                target,
                message.to_string().replace('"', r#"\""#)
            ) + "\n"
        } else {
            format!("[{timestamp}] [{level:5}] [{target}] {message}\n")
        }
    }
}

impl Log for DualLogger {
    fn enabled(&self, metadata: &Metadata) -> bool {
        metadata.level() <= self.console_level || 
        metadata.level() <= self.file_level
    }

    fn log(&self, record: &Record) {
        // Console output
        if record.level() <= self.console_level {
            eprint!("{}", self.format_console(record));
        }

        // File output
        if record.level() <= self.file_level {
            if let Some(ref file) = self.file {
                let formatted = self.format_file(record);
                if let Ok(mut file) = file.lock() {
                    let _ = file.write(formatted.as_bytes());
                }
            }
        }
    }

    fn flush(&self) {
        if let Some(ref file) = self.file {
            if let Ok(mut file) = file.lock() {
                let _ = file.writer.flush();
            }
        }
    }
}
```

### Structured Event Logging

```rust
// src/logging/events.rs
use serde::Serialize;
use std::sync::mpsc::{Sender, Receiver, channel};
use std::thread;

/// Structured event for analytics and debugging
#[derive(Debug, Clone, Serialize)]
pub struct StructuredEvent {
    pub timestamp: String,
    pub event_type: String,
    pub component: String,
    pub data: serde_json::Value,
}

pub struct EventLog {
    sender: Sender<StructuredEvent>,
}

impl EventLog {
    pub fn new(log_path: PathBuf) -> Self {
        let (sender, receiver) = channel();

        // Background thread for async event writing
        thread::spawn(move || {
            Self::event_writer(receiver, log_path);
        });

        Self { sender }
    }

    fn event_writer(receiver: Receiver<StructuredEvent>, log_path: PathBuf) {
        let mut file = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&log_path)
            .ok();

        while let Ok(event) = receiver.recv() {
            if let Some(ref mut f) = file {
                let json = serde_json::to_string(&event).unwrap_or_default();
                let _ = writeln!(f, "{}", json);
            }
        }
    }

    pub fn log<T: Serialize>(&self, event_type: &str, component: &str, data: T) {
        let event = StructuredEvent {
            timestamp: chrono::Utc::now().to_rfc3339(),
            event_type: event_type.to_string(),
            component: component.to_string(),
            data: serde_json::to_value(data).unwrap_or(serde_json::Value::Null),
        };
        let _ = self.sender.send(event);
    }
}

// Convenience macros
#[macro_export]
macro_rules! log_event {
    ($logger:expr, $event_type:expr, $component:expr, $($field:tt)*) => {
        $logger.log($event_type, $component, serde_json::json!($($field)*))
    };
}

// Usage:
// log_event!(event_log, "volume_change", "daemon", {
//     "old_volume": 50,
//     "new_volume": 55,
//     "mode": "volume"
// });
```

### Log Viewer CLI

