### Low Battery Notifications

```rust
// src/notifications.rs

use crate::battery::BatteryStatus;

pub struct NotificationManager {
    last_warning_percent: Option<u8>,
    notification_thresholds: Vec<u8>,  // e.g., [20, 10, 5]
}

impl NotificationManager {
    pub fn check_battery(&mut self, status: &BatteryStatus) {
        let Some(percent) = status.percent else { return };

        // Find the highest threshold we've crossed
        for &threshold in &self.notification_thresholds {
            if percent <= threshold {
                // Only notify if we haven't already for this threshold
                if self.last_warning_percent.map(|p| p > threshold).unwrap_or(true) {
                    self.send_low_battery_notification(percent, threshold);
                    self.last_warning_percent = Some(percent);
                }
                break;
            }
        }
    }

    fn send_low_battery_notification(&self, percent: u8, threshold: u8) {
        let (title, body, urgency) = if threshold <= 10 {
            (
                "Surface Dial Battery Critical",
                format!("Battery at {}%. Replace batteries soon.", percent),
                Urgency::Critical,
            )
        } else {
            (
                "Surface Dial Battery Low",
                format!("Battery at {}%.", percent),
                Urgency::Normal,
            )
        };

        #[cfg(target_os = "macos")]
        notify_macos(&title, &body);

        #[cfg(target_os = "linux")]
        notify_linux(&title, &body, urgency);

        #[cfg(target_os = "windows")]
        notify_windows(&title, &body);
    }
}
```

### Platform-Specific Notifications

```rust
// macOS: Use NSUserNotificationCenter or UNUserNotificationCenter
#[cfg(target_os = "macos")]
fn notify_macos(title: &str, body: &str) {
    use std::process::Command;
    // Use osascript for simplicity, or objc bindings for native
    Command::new("osascript")
        .args(["-e", &format!(
            r#"display notification "{}" with title "{}""#,
            body, title
        )])
        .output()
        .ok();
}

// Linux: Use notify-send (libnotify)
#[cfg(target_os = "linux")]
fn notify_linux(title: &str, body: &str, urgency: Urgency) {
    use std::process::Command;
    let urgency_str = match urgency {
        Urgency::Critical => "critical",
        Urgency::Normal => "normal",
        Urgency::Low => "low",
    };
    Command::new("notify-send")
        .args(["-u", urgency_str, title, body])
        .output()
        .ok();
}

// Windows: Use ToastNotification
#[cfg(target_os = "windows")]
fn notify_windows(title: &str, body: &str) {
    // Use windows-rs or powershell
    use std::process::Command;
    let script = format!(
        r#"[Windows.UI.Notifications.ToastNotificationManager, Windows.UI.Notifications, ContentType = WindowsRuntime] | Out-Null
        $template = [Windows.UI.Notifications.ToastTemplateType]::ToastText02
        $xml = [Windows.UI.Notifications.ToastNotificationManager]::GetTemplateContent($template)
        $text = $xml.GetElementsByTagName("text")
        $text[0].AppendChild($xml.CreateTextNode("{}")) | Out-Null
        $text[1].AppendChild($xml.CreateTextNode("{}")) | Out-Null
        $toast = [Windows.UI.Notifications.ToastNotification]::new($xml)
        [Windows.UI.Notifications.ToastNotificationManager]::CreateToastNotifier("Surface Dial").Show($toast)"#,
        title, body
    );
    Command::new("powershell")
        .args(["-Command", &script])
        .output()
        .ok();
}
```

